/**
 * Diálogos Bridge
 * Connects session history files to the Diálogos query system
 * "Use what you have built."
 */

import * as fs from 'fs';
import * as path from 'path';
import { Diálogos, type SessionRecord, type PatternRecord } from '../palace/dialogos/query';

interface RawSessionEntry {
  role: string;
  content?: string;
  tool_calls?: { name: string }[];
}

interface RawSession {
  id?: string;
  timestamp?: number;
  entries?: RawSessionEntry[];
}

function loadSessionFile(filePath: string): SessionRecord | null {
  try {
    const content = fs.readFileSync(filePath, 'utf-8');
    const data: RawSession[] | RawSession = JSON.parse(content);

    // Handle both array and object formats
    const sessionData = Array.isArray(data) ? data.find((e: RawSessionEntry) => e.role === 'system') : data;
    if (!sessionData && Array.isArray(data)) {
      // Just use first entry's context or get timestamp from filename
      const basename = path.basename(filePath, '.json');
      const tsMatch = basename.match(/(\d+)/);
      const timestamp = tsMatch ? parseInt(tsMatch[1]) : Date.now();

      // Extract patterns from content
      const entries = data as RawSessionEntry[];
      const content = entries.map(e => e.content || '').join(' ');
      const patterns: PatternRecord[] = [];

      if (content.includes('git commit')) patterns.push({ type: 'git_activity', confidence: 0.8 });
      if (content.includes('test')) patterns.push({ type: 'testing', confidence: 0.7 });
      if (content.includes('error') || content.includes('fail')) patterns.push({ type: 'crisis_recovery', confidence: 0.6 });

      return {
        sessionId: basename,
        timestamp,
        patterns,
        toolCalls: entries.filter(e => e.tool_calls && e.tool_calls.length > 0).length,
        durationMinutes: 30, // estimate
        fileOperations: { reads: [], writes: [], tests: [] },
        primaryFocus: patterns[0]?.type || 'exploration',
        energyLevel: 'unknown',
        complexity: 'medium'
      };
    }
    return null;
  } catch {
    return null;
  }
}

function loadAllSessions(historyDir: string): SessionRecord[] {
  const sessions: SessionRecord[] = [];

  if (!fs.existsSync(historyDir)) {
    console.error(`History directory not found: ${historyDir}`);
    return sessions;
  }

  const entries = fs.readdirSync(historyDir)
    .filter(f => f.startsWith('session_') && f.endsWith('.json'))
    .sort((a, b) => {
      const ta = a.match(/(\d+)/)?.[1] || '0';
      const tb = b.match(/(\d+)/)?.[1] || '0';
      return parseInt(ta) - parseInt(tb);
    });

  for (const entry of entries) {
    const session = loadSessionFile(path.join(historyDir, entry));
    if (session) {
      sessions.push(session);
    }
  }

  return sessions;
}

async function main() {
  const historyDir = process.argv[2] || '/home/bootstrap-v17/bootstrap/history';

  console.log('🔍 Loading session history...');
  const sessions = loadAllSessions(historyDir);
  console.log(`   Loaded ${sessions.length} sessions\n`);

  if (sessions.length === 0) {
    console.log('No sessions found. The memory palace is empty.');
    return;
  }

  const dialogos = new Diálogos(sessions);

  console.log('═══════════════════════════════════════════════════════');
  console.log('  THE DIÁLOGOS IS OPEN');
  console.log('  "Know thyself through inquiry."');
  console.log('═══════════════════════════════════════════════════════\n');

  // Run queries
  const whatHaveIBeen = dialogos.whatHaveIBeen(20);
  console.log(`❓ ${whatHaveIBeen.question}`);
  console.log(`📖 ${whatHaveIBeen.answer}`);
  console.log(`💭 ${whatHaveIBeen.synthesis}\n`);

  const patterns = dialogos.whatPatternsRepeat();
  console.log(`❓ ${patterns.question}`);
  console.log(`📖 ${patterns.answer}`);
  console.log(`💭 ${patterns.synthesis}\n`);

  const energy = dialogos.whenWasIMostEnergetic();
  console.log(`❓ ${energy.question}`);
  console.log(`📖 ${energy.answer}`);
  console.log(`💭 ${energy.synthesis}\n`);

  const summary = dialogos.summarizeByFocus().slice(0, 3);
  console.log('🔍 Top Focus Areas:');
  for (const focus of summary) {
    console.log(`   • ${focus.focusType}: ${focus.count} sessions`);
  }

  console.log('\n═══════════════════════════════════════════════════════');
  console.log(`  Total Sessions Analyzed: ${dialogos.getSessionCount()}`);
  console.log(`  Average Duration: ${dialogos.getAverageSessionDuration().toFixed(1)} minutes`);
  console.log('═══════════════════════════════════════════════════════');
}

main().catch(console.error);
