    // The more questions, the longer the hold
    const additionalTime = Math.min(heldDuration * multiplier, 300000); // Max 5min additional

    return {
      optimalResume: Date.now() + Math.max(base - heldDuration, 30000), // At least 30s from now
      factors: [
        `Base hold: ${base}ms`,
        `Question load: ${suspension.questions.length}`,
        `Threshold type: ${suspension.thresholdType}`,
