  | 'intuition'       // Something feels missing, can't articulate
  | 'transition'      // Phase shift in understanding required
  | 'emergence';      // Waiting for pattern to crystallize

export type Urgency = 'immediate' | 'soon' | 'when-ready' | 'eventually';

